var e=JSON.parse(`[{"id":"L1_1","type":"subtitle","speaker":null,"text":{"KOREA":"샤레이드 건틀렛 본선 8강 토너먼트.\\n시작 세 시간 전.","JPN":"シャレードガントレット本戦準々決勝トーナメント。\\n開始3時間前","ENG":"Charade Gauntlet elimination quarterfinals tournament.\\n3 hours before starting.","TWN":"查雷德聖鎧決賽八強淘汰賽。\\n開始前三小時。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"EMPLOY_PRIDE_NULL_NULL","text":{"KOREA":"저… 다시 한번 확인하겠습니다.","JPN":"ええと……もう一度確認します。","ENG":"Um... I'll confirm just one more time.","TWN":"我……再確認一次。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EMPLOY_PRIDE_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L4_1","type":"dialog","speaker":"EMPLOY_PRIDE_NULL_NULL","text":{"KOREA":"카나리아의 추가 엔트리 멤버의 경우, 선수 등록을 위해 두 시간 전까지는 경기장에 도착하셔야 합니다.","JPN":"カナリアの追加エントリーメンバーは、選手登録のために、2時間前には競技場に到着していただく必要があります。","ENG":"Any additional entry for Canary Squad must arrive at the stadium at least two hours before the match.","TWN":"金絲雀的額外參賽成員需要在兩小時前到達賽場進行選手登記。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EMPLOY_PRIDE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"EMPLOY_PRIDE_NULL_NULL","text":{"KOREA":"물론, 시간 외 경기장 난입은 불가능하고요.","JPN":"もちろん、時間外の競技場への乱入は禁止です。","ENG":"Of course, entering the arena outside that window is prohibited.","TWN":"當然，規定時間外無法進入競技場。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EMPLOY_PRIDE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"걱정 말게. 그 둘이라면 늦지 않을 테니.","JPN":"心配いらない。彼らなら間に合うはずだ。","ENG":"Don't worry. Those two won't be late.","TWN":"別擔心。那兩個人不會遲到的。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EMPLOY_PRIDE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"펠리세트와 스키너 양도 라이카 양의 병문안에 갔을 뿐이니, 곧 도착할 걸세.","JPN":"フェリセットとスキナー君も、ライカ君の見舞いに行っただけだから、すぐ着くはずさ。","ENG":"Félicette and Skinner just went to visit Laika in the hospital. They should be back soon.","TWN":"費莉塞特和史金納只是去探望萊卡，很快就會到的。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EMPLOY_PRIDE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"EMPLOY_PRIDE_NULL_NULL","text":{"KOREA":"예. 그럼 팀 엔트리는 건네주신 것과 동일하게 진행하겠습니다.","JPN":"はい。では、チームのエントリーはお渡しいただいた通り進めさせていただきます。","ENG":"Understood. Then I'll proceed with the team entry as previously submitted.","TWN":"好的，那麼團隊名單將按照你提供的進行。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EMPLOY_PRIDE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"EMPLOY_PRIDE_NULL_NULL","text":{"KOREA":"규칙을 어겨 발생하는 페널티는 온전히 팀의 몫이니, 이 점 명심해주시길.","JPN":"ルールを破って発生するペナルティについては、チームの責任となりますから、どうかご注意を。","ENG":"Please keep in mind that any penalties from rule violations fall entirely on the team.","TWN":"違反規則所產生的懲罰將完全由團隊承擔，請牢記這一點。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EMPLOY_PRIDE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"저기, 사장님.","JPN":"ねえ、社長。","ENG":"Hey, Boss.","TWN":"那個，老闆。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L15_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"미나 양도 그 둘이 걱정되나?","JPN":"ミナ君も二人が心配なのか？","ENG":"Are you worried about those two too, Mina?","TWN":"米娜也擔心那兩個人嗎？"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"교체 선수가 늦을 거라는 걱정은 안 해. 그냥, 그 둘을 선택한 이유가 있나 싶어서.","JPN":"交代選手が遅れるとは思わないよ。ただ、その二人を選んだ理由があるのかなと思って。","ENG":"Not worried about them being late. I was just curious why you picked them.","TWN":"不是擔心替補選手會遲到。我只是好奇，為什麼選擇了那兩個人。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"팀으로 움직이는 거라면 회사 사람들이 낫지 않았나 싶은데.","JPN":"チームで動くのなら、会社の人のほうがよかったんじゃないの？","ENG":"If it's about teamwork, wouldn't using our company employees be better?","TWN":"如果是團隊行動的話，公司的人不是更好嗎？"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":null,"text":{"KOREA":"부사장은 자네가 설득하고?","JPN":"副社長は君が説得するのかい？","ENG":"And you'd be the one to convince the Vice President?","TWN":"你跟副總說？"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":null,"text":{"KOREA":"걱정 말게. 여차하면 미나 양이 뛰면 그만 아닌가?","JPN":"心配は無用だ。いざとなればミナ君が参加すればいい。","ENG":"Besides, in the worst-case scenario, you can always jump in.","TWN":"不用擔心。實在不行的話，讓米娜來就行了吧？"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"농담하는 걸 보면 믿는 구석이 있는 모양이네.","JPN":"そんな冗談が言えるってことは、なにか確信があるんだね。","ENG":"You must be pretty confident to joke like that.","TWN":"看你開玩笑的樣子，看來是有留兩手啊。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"물론이지. 나름 전력차를 메울 수 있는 요소를 갖춘 친구들로 선별했다네.","JPN":"もちろんだ。戦力差を埋められる要素を考慮した人選だ。","ENG":"Of course. I chose them because they have what it takes to close the power gap.","TWN":"當然。我挑選了一些能夠彌補戰力差距的朋友。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"무엇보다 우리에겐 노엘 양이 있지 않나?","JPN":"何より、こちらにはノエル君がいるじゃないか。","ENG":"And above all, we have Noelle on our side.","TWN":"最重要的是，我們有洛艾兒，不是嗎？"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"네-엡! 이 노엘. 적 장수의 목을 단숨에 베어오겠습니다!","JPN":"はーいっ！　このノエルが敵将の首を刈り取ってみせます！","ENG":"Yup! I, Noelle, shall bring back the enemy commander's head in one stroke!","TWN":"是-嗯！我是洛艾兒。我會一口氣砍下敵將的頭顱！"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_BEEP2"},{"id":"L28_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"좋은 기세일세. 코핀 컴퍼니 헤드 스쿼드 멤버의 힘을 저들에게 보여주세나.","JPN":"いい勢いだ。コフィンカンパニー主要メンバーの力を彼らに見せつけてくれ。","ENG":"That's the spirit. Show them the strength of a Head Squad member from Coffin Company.","TWN":"氣勢不錯。讓他們見識一下科芬公司主力小隊成員的實力吧。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"펜릴 소대 스타일로 말이죠?","JPN":"フェンリル小隊のスタイルでですね？","ENG":"You got it, Fenrir Squad style, right?","TWN":"芬里爾小隊風格的說法嗎？"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":null,"text":{"KOREA":"소대장 스타일로 부탁하네.","JPN":"小隊長スタイルで頼む。","ENG":"Preferably, Division Commander style.","TWN":"請以小隊長的風格來做。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":null,"text":{"KOREA":"미나 양처럼 싸우는 게 좋겠군.","JPN":"ミナ君スタイルがいいな。","ENG":"Fighting like Mina would be best.","TWN":"像米娜那樣戰鬥會比較好。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"맡겨만 주세요, 사장님! 적을 <color=#ff3636>[검열됨]</color>해서 <color=#ff3636>[검열됨]</color>하겠습니다!!","JPN":"任せてください、社長！　敵を<color=#ff3636>[検閲済]</color>して<color=#ff3636>[検閲済]</color>してやります！！","ENG":"Leave it to me, Boss! I'll <color=#ff3636>[BLEEP]</color> the enemy and then <color=#ff3636>[BLEEP]</color> them!","TWN":"交給我們吧，老闆！我們會<color=#ff3636>[已審查]</color>敵人並<color=#ff3636>[已審查]</color>他們！！"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"……아니, 그렇게까지 안 하거든.","JPN":"……いや、そこまではやってないから。","ENG":"...Okay, I don't go that far.","TWN":"……不，我不會做到那種程度。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_HATE"}}}},{"id":"L37_1","type":"dialog","speaker":"EMPLOY_PRIDE_NULL_NULL","text":{"KOREA":"실례합니다. 카나리아 팀의 코치 분 계실까요?","JPN":"失礼します。カナリアチームのコーチの方、いらっしゃいますか？","ENG":"Excuse me, is the coach for Canary Squad here?","TWN":"打擾一下，請問金絲雀隊的教練在嗎？"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EMPLOY_PRIDE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"코치라면 나네. 무슨 일인가?","JPN":"コーチは私だ。どうかしたかね？","ENG":"That would be me. What is it?","TWN":"如果是教練的話，那就是我了。有什麼事嗎？"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EMPLOY_PRIDE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"EMPLOY_PRIDE_NULL_NULL","text":{"KOREA":"밖에서 코치님을 찾는 분이 계십니다.","JPN":"外に、コーチを探している方がいらっしゃいます。","ENG":"Someone outside is asking for you.","TWN":"外面有人在找教練。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EMPLOY_PRIDE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"EMPLOY_PRIDE_NULL_NULL","text":{"KOREA":"외부인인 줄 알았는데 팀 카나리아의 ID카드를 지니고 계셔서요.","JPN":"部外者だと思ったんですが、チームカナリアのIDカードを持っていたので。","ENG":"We thought she was a civilian, but she had an official Canary Squad ID.","TWN":"我以為你是外人，但你持有金絲雀小隊的ID卡。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EMPLOY_PRIDE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"EMPLOY_PRIDE_NULL_NULL","text":{"KOREA":"모르시는 일이라면 저희 쪽에서 대처하겠습니다만… 어떻게 할까요?","JPN":"知らない方でしたら、こちらで対応いたしますが……どうしましょうか。","ENG":"If this is news to you, we'll take care of it. How would you like to proceed?","TWN":"如果是你不知情的事情，我們這邊會處理……你覺得怎麼樣？"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EMPLOY_PRIDE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"우리 쪽 손님이 도착한 모양이군. 알려줘서 고맙네.","JPN":"うちの客が来たんだろう。教えてくれてありがとう。","ENG":"Sounds like our guest has arrived. Thank you.","TWN":"看來我們的客人已經到了。謝謝你告訴我。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EMPLOY_PRIDE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"금방 갈 테니 기다려달라 전해주겠나?","JPN":"すぐ向かうので少し待ってもらうように伝えてくれるか？","ENG":"Tell her I'll be there shortly.","TWN":"請告訴他們，我馬上就到，請稍等。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EMPLOY_PRIDE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"EMPLOY_PRIDE_NULL_NULL","text":{"KOREA":"네. 알겠습니다.","JPN":"はい、かしこまりました。","ENG":"Yes, understood.","TWN":"好的，知道了。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EMPLOY_PRIDE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"나도 따라갈까?","JPN":"私も行こうか？","ENG":"Want me to come too?","TWN":"我也要跟著去嗎？"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L50_1","type":"dialog","speaker":null,"text":{"KOREA":"샤레이드 중심지인 상업지구에서 위험한 일이 뭐가 있겠나?","JPN":"シャレードの中心地であるこの商業地区で危険なことは起こらないだろう。","ENG":"What danger could there be in Charade's central commercial district?","TWN":"在查雷德的商業區中心會有什麼危險的事情呢？"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":null,"text":{"KOREA":"노엘 양을 혼자 놔두고?\xA0\xA0","JPN":"ノエル君を置いていくのか？\xA0\xA0","ENG":"While leaving Noelle alone?\xA0\xA0","TWN":"把洛艾兒一個人留下？"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"하긴, 그건 그렇지.","JPN":"まあ、それもそうだね。","ENG":"Fair point.","TWN":"是啊，那倒是。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"여기서 기다리고 있을게. 다녀와, 사장님.","JPN":"じゃあここで待ってる。いってらっしゃい、社長。","ENG":"I'll wait here. Take care, Boss.","TWN":"我會在這裡等著。去吧，老闆。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"음? 자네는……?","JPN":"ん？　君は……？","ENG":"Hmm? And you are...?","TWN":"嗯？你是……？"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_MOVEMENT_03"},{"id":"L8_1","type":"dialog","speaker":null,"text":{"KOREA":"예상치 못한 손님이군.","JPN":"予想外の来客だな。","ENG":"An unexpected visitor.","TWN":"意想不到的客人啊。"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":null,"text":{"KOREA":"그건 조디악 나이츠의 새로운 제복인가?","JPN":"それはゾディアックナイツの新しい制服か？","ENG":"Is that the new uniform of the Zodiac Knights?","TWN":"那是十二宮騎士的新制服嗎？"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"이야기를 나누는 것은 이번이 처음이군요.","JPN":"お話するのはこれが初めてですね。","ENG":"This is our first conversation, isn't it?","TWN":"這是我們第一次談話。"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L12_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"관리자 님과의 만남을 위해 신분을 속인 무례를 부디 용서해주시길.\xA0\xA0","JPN":"管理者と会うために身分を偽った無礼をどうかお許しください。\xA0\xA0","ENG":"I apologize for the deception, but it was the only way I could meet you.\xA0\xA0","TWN":"請原諒我為了與管理者見面而隱瞞身份的無禮行為。\xA0\xA0"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"지금은 그냥 코치일세. 너무 격식 차리지 말게나.","JPN":"今はただのコーチだ。そう堅苦しくすることはない。","ENG":"Just call me Coach for now. No need for formalities.","TWN":"現在我只是個教練而已。不要太拘謹了。"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"설마 조디악 나이츠의 단장이 나를 찾아올 줄은 몰랐군.","JPN":"まさかゾディアックナイツの団長が私を訪ねてくるとはね。","ENG":"Didn't expect the Captain of the Zodiac Knights to come find me.","TWN":"沒想到十二宮騎士團的團長會來找我。"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"아뇨. 오늘은 기사의 신분으로 이곳에 온 것이 아닙니다.","JPN":"今日は騎士の身分でここに来たわけではありません。","ENG":"No. I'm not here as a knight today.","TWN":"不，今天我不是以騎士的身份來到這裡的。"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"지금의 전 기사단과 관계없는 외부인에 불과하니까요.","JPN":"今の私は、騎士団とは無関係の部外者に過ぎませんので。","ENG":"Right now, I'm just an outsider with no connection to the current Order.","TWN":"我只是與現在的前騎士團無關的外部人士罷了。"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":null,"text":{"KOREA":"클리포트 게임의 영향인가?","JPN":"クリフォトゲームの影響か？","ENG":"Because of the Qliphoth Game?","TWN":"是因為逆卡巴拉遊戲嗎？"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":null,"text":{"KOREA":"괜찮다면 자세한 이야기를 들려줄 수 있겠나?","JPN":"よければ詳しい話を聞かせてくれるか？","ENG":"Would you be willing to tell us more?","TWN":"如果可以的話，你能詳細跟我說說嗎？"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"죄송합니다. 기사단 내부의 문제라 선뜻 내뱉기는 어렵군요.","JPN":"申し訳ありません。騎士団内部の問題なので、軽々しく口にすることはできません。","ENG":"I'm sorry. It's an internal matter. I'd rather not speak about it casually.","TWN":"抱歉，這是騎士團內部的問題，我不便輕易發表意見。"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"과연, 그 문제가 나를 찾아온 이유와 관련 있겠군.","JPN":"なるほど、その問題というのが私を訪ねた理由と関係がありそうだな。","ENG":"I see. Then I assume it's connected to why you came looking for me.","TWN":"果然，這個問題和你找我的原因有關吧。"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"사정은 알았으니 편하게 말해보게.","JPN":"事情はわかった。気軽に話したまえ。","ENG":"I understand. Speak freely.","TWN":"既然了解情況了，就請輕鬆地說出來吧。"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"……예. 감사합니다.","JPN":"……はい、感謝いたします。","ENG":"...Thank you.","TWN":"……是的，謝謝。"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"실례가 안된다면, 관리자님의 힘을 빌려 만나고 싶은 사람이 있습니다.","JPN":"失礼でなければ、管理者の力をお借りして会いたい人がいます。","ENG":"If it's not too much trouble, there's someone I'd like to meet with your help.","TWN":"如果不介意的話，我想借助管理者的力量去見一個人。"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L28_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"실례는 무슨. 자네들에겐 진 빚이 있으니 힘이 닿는다면 얼마든지 도와야지.","JPN":"失礼も何も。君たちには借りがある。私にできることならいくらでも手伝おう。","ENG":"No trouble at all. I owe you all a debt. I'll help however I can.","TWN":"哪裡的話。我欠你們的債，如果能幫上忙的話，當然要幫忙了。"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"내가 누구를 만나게 해주면 되나?","JPN":"誰に会いたいのかね？","ENG":"So who is it you want to meet?","TWN":"我該讓你見誰呢？"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"……오지만디아스.","JPN":"……オジマンディアス。","ENG":"...Ozymandias.","TWN":"……奧茲曼迪亞斯。"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"이곳에서 건틀렛 챔피언으로 불리는 자입니다.","JPN":"ここでガントレットチャンピオンと呼ばれる者です。","ENG":"The one they call the Gauntlet Champion here.","TWN":"是這裡被稱為聖鎧冠軍的人。"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"과연. 굳이 여기까지 찾아온 이유가 있었군.","JPN":"なるほど。わざわざここまでやって来たのはそのためか。","ENG":"Ah, I see. So that's why you came.","TWN":"果然，看來你有理由特意找到這裡來。"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"다만 유감일세. 최고 관리자라 해도 권한 정지상태라서 말이야.","JPN":"しかし残念だ。最高管理者とはいえ、今は権限を停止されているのでね。","ENG":"Unfortunately, even as the Supreme Administrator, I'm currently suspended.","TWN":"不過很遺憾。即使是最高管理者，也處於許可權凍結狀態。"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"다른 사람도 아닌 관리국 공인 카운터를 불러내는 건 힘들겠어.","JPN":"他でもない、管理局公認のカウンターを呼び出すのは難しそうだ。","ENG":"And calling out an Administration confirmed Counter isn't easy, even for me.","TWN":"召喚管理局認證的制裁者可不是件容易的事。"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"그렇, 습니까……?","JPN":"そう、ですか……","ENG":"I see...","TWN":"是嗎……？"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"죄송합니다. 제가 무리한 부탁을 드렸군요.","JPN":"申し訳ありません。無理なお願いをしてしまいましたね。","ENG":"I'm sorry. That was a selfish request.","TWN":"對不起。我提出了過分的請求。"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":null,"text":{"KOREA":"다만, 그녀를 만날 방법이 없는 건 아니야.","JPN":"ただ、彼女に会える方法がまったくないわけではない。","ENG":"Still, it's not like there's no way to meet her.","TWN":"不過，也不是沒有辦法見到她。"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"다른 방법이 있다는 말씀입니까?","JPN":"他にも方法があるということですか？","ENG":"You mean there's another way?","TWN":"你是說有其他方法嗎？"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"자랑은 아니지만 우리 쪽 팀원 한 명이 오지만디아스와 악연으로 얽혀 있네.","JPN":"自慢ではないが、うちのチームメンバーの1人が、オジマンディアスと腐れ縁でね。","ENG":"As it happens, one of my squad members has a bit of history with Ozymandias.","TWN":"雖然不是值得炫耀的事情，但我們團隊裡有一個成員和奧茲曼迪亞斯有過節。"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"자네가 찾지 않아도 그녀는 자연스레 오늘 경기를 보러 오겠지.","JPN":"君が探さなくても、彼女は今日の試合を観に来るはずだ。","ENG":"She's bound to show up for today's match regardless.","TWN":"即使你不找她，她也會自然地來看今天的比賽吧。"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"상대가 기사단이기도 하니 말씀처럼 될 지도 모르겠습니다만…….","JPN":"相手が騎士団だけあって、その通りかもしれませんが……","ENG":"With the match being against the Order, that may well be the case...","TWN":"對方畢竟是騎士團，可能會如你所說……"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"사정 상, 경기장 내부로는 들어가기 어렵겠군요.","JPN":"事情があって、競技場の内部には入りづらいのです。","ENG":"But I don't think I can get inside the arena myself.","TWN":"由於情況，上不了競技場內部了。"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"얼핏 듣기로 챔피언은 매번 동쪽 입구와 이어진 대로를 통해 입장한다더군.","JPN":"聞いた話によると、チャンピオンは毎回東ゲートにつながる大通りから入場するらしい。","ENG":"Word is, she always enters via the boulevard connected to the east gate.","TWN":"我聽說冠軍每次都是通過連接東側入口的大道入場的。"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"개인적인 일로 경기를 보러 온 거라면 수행인을 대동하지도 않겠지.","JPN":"個人的に試合を観に来たのであれば、付き添いの者もいないはずだ。","ENG":"If she's attending on her own, she probably won't have an escort either.","TWN":"如果是因為個人事務來看比賽的話，就不會帶人了吧。"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"경기장 내부로 들어가기 어렵다면, 그전에 미리 만나면 되지 않겠나?","JPN":"競技場に入れないのなら、入る前に会えばいいのではないか？","ENG":"If you can't meet her inside, then meet her before she goes in.","TWN":"如果難以進入競技場內部，那就提前見面吧？"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"감사합니다. 이 빚은 언젠가 갚겠습니다.","JPN":"ありがとうございます。このご恩はいつか必ずお返しします。","ENG":"Thank you. I'll repay this debt someday.","TWN":"非常感謝。這個人情我會找機會還的。"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"버밍엄 교수에 관한 건 묻지 않는 건가?","JPN":"バーミンガム教授のことは聞かないのか？","ENG":"You're not going to ask about Professor Birmingham?","TWN":"不問伯明罕教授的事嗎？"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"……이유가 있었다 한들 그가 마왕의 사도로서 세계에 위협을 가한 것은 사실입니다.\xA0\xA0","JPN":"……理由があったとはいえ、彼が魔王の使徒として世界を脅かしていたことは事実です。\xA0\xA0","ENG":"...Even if he had his reasons, he still endangered the world as an Apostle.\xA0\xA0","TWN":"……即便有理由，她作為魔王的使徒對世界造成威脅也是事實。\xA0\xA0"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"관리국이 버밍엄 교수의 옛 거처를 조사하고 있다는 이야기는 들었으나…….","JPN":"バーミンガム教授が住んでいた場所について、管理局が調査を行っているという話は聞きましたが……","ENG":"I heard the Administration is investigating his old residence...","TWN":"聽說管理局正在調查伯明罕教授的舊居……"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"그 결과에 관해 제게 파헤칠 자격은 없겠죠.","JPN":"その結果を探る資格は私にはありません。","ENG":"But I don't have the right to pry into the results.","TWN":"我沒有資格去探究那個結果。"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그렇다기에는 관리국 또한 클리포트 게임에서 그림자의 협력을 받았지.","JPN":"しかし、管理局もクリフォトゲームでシャドウの助けを借りていた。","ENG":"And yet, the Administration also accepted help from Shadows in the Qliphoth Game.","TWN":"要這麼說的話，管理局在逆卡巴拉遊戲中也得到了暗影的協助。"},"stage":{"bg":"MS_1106","bgm":"UI_BASE_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"자네 입장에선 그들을 죽이지 않고 투항시키는 것이 하나의 방안이라 여겼을 걸세.","JPN":"君の立場からすると、彼らを殺さず投降させることも、一つの方法だと考えたのだろう。","ENG":"I imagine you saw sparing them as a viable option.","TWN":"從你的立場來看，讓他們投降而不是殺死他們可能是一個解決方案。"},"stage":{"bg":"MS_1106","bgm":"UI_BASE_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"……무슨 말씀을 하시려는 건지 모르겠군요.","JPN":"……何のことかわかりません。","ENG":"...I don't understand what you're implying.","TWN":"……我不明白你想說什麼。"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_LIGHT_02"},{"id":"L12_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"결국 현 상황의 모든 것은 최고 관리자인 내가 초래한 것이나 다름없네.","JPN":"つまり、この状況のすべては最高管理者である私が招いたも同然だ。","ENG":"In the end, everything that's happening now is partly my fault.","TWN":"最終，現狀的一切都是由我這個最高管理者引發的，沒什麼不同。"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"자네가 그 결과로 인해 골머리를 앓고 있다면, 그걸 해결하는 건 또한 내 업이겠지.","JPN":"そのせいで君を悩ませてしまったのなら、それを解決するのも私の責務だろう。","ENG":"If you're suffering from the outcome, then I should be the one to set it right.","TWN":"如果你因為那個結果而煩惱，那麼解決它也是我的責任吧。"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"그러다, 제가 관리자님을 베러 들면 어쩌실 겁니까?","JPN":"私が管理者を斬りかかったりでもしたら、どうするつもりですか？","ENG":"And what if I decide to come after you next?","TWN":"如果我把你給打倒了，你會怎麼辦呢？"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":null,"text":{"KOREA":"아프지 않게 부탁하네.","JPN":"痛くないように頼む。","ENG":"At least make it quick.","TWN":"請不要讓我受傷。"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":null,"text":{"KOREA":"미인에게 죽는다면 호상이지.","JPN":"美人に殺されるなんて、悪くない死に方だ。","ENG":"Dying at the hands of a beauty wouldn't be the worst way to go.","TWN":"死在美人手中，也算是死得其所了。"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"솔직한 심정으로는 관리국을 원망하는 마음이 없진 않습니다.","JPN":"正直、管理局を恨む気持ちもあります。","ENG":"I won't pretend I don't resent the Administration.","TWN":"說實話，我心裡還是有些埋怨管理局的。"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"하지만…….","JPN":"しかし……","ENG":"But...","TWN":"但是……"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"대련 도중 자네의 검은 나를 날카롭게 겨눴는데, 정작 전장에서는 본래의 쓰임조차 잃었군.","JPN":"かつての手合わせで、君の剣は鋭く私を狙えていた。だが、肝心な戦場では本来の力を発揮できていないな。","ENG":"Your sword was sharp when we sparred, but now on the battlefield, it's forgotten its purpose.","TWN":"對練時你的劍鋒直指我，而在戰場上卻失去了原本的用途。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"UI_BASE_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_LIGHT_02"},{"id":"L23_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"아무런 각오도 없이 전장에 서는 게, 자네가 말하는 <color=#ffd34c>기사도</color>인가?","JPN":"何の覚悟もなく戦場に立つのが、君の言う<color=#ffd34c>騎士道</color>なのか？","ENG":"To stand on the field without resolve. Is that what you call <color=#ffd34c>chivalry</color>?","TWN":"毫無覺悟地站在戰場上，就是你所說的<color=#ffd34c>騎士精神</color>嗎？"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"UI_BASE_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"싸울 의지도, 무언가를 포기할 각오조차 없는 이에게 별의 무구가 응답할 리 없지.","JPN":"戦う意志も、何かを捨てる覚悟もない者に、星の武具が応えるはずがない。","ENG":"No Star Armament would answer someone with no will to fight, no readiness to sacrifice something.","TWN":"既沒有戰鬥的意志，也沒有放棄某些東西的覺悟，星之武具是不會回應這種人的。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"UI_BASE_02","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_LIGHT_02"},{"id":"L27_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"그만 끝내게. 이게 내가 자네에게 해줄 수 있는 마지막 배려야.","JPN":"もう終わりにしたまえ。これが私が君にしてやれる最後の気遣いだ。","ENG":"End this. This is the last kindness I can offer you.","TWN":"就此結束吧。這是我能給你的最後的關照了。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"UI_BASE_02","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"하지만, 결국 모든 일은 제 무능함으로부터 초래된 일입니다.","JPN":"しかし、結局すべては私の無能さが招いた結果です。","ENG":"But it's all my fault. Every failure stems from my own incompetence.","TWN":"但是，最終所有事情都是由於我的無能而引起的。"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"다른 사람을 원망하기보다… 제 스스로가 바뀌어야겠죠.","JPN":"他人を恨むよりは……自分自身が変わる必要があるでしょう。","ENG":"I need to change... not blame others.","TWN":"與其責怪別人……我自己應該改變才對。"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":null,"text":{"KOREA":"앞으로는 어쩔 셈인가?","JPN":"これからどうするつもりだ？","ENG":"What will you do now?","TWN":"接下來打算怎麼辦？"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"전임 기사단장이었던 제 오빠는 모종의 이유로 버고 소드를 내려놓은 채 종적을 감췄습니다.","JPN":"前騎士団長の兄は、なんらかの理由でヴァルゴソードを手放し、行方をくらましました。","ENG":"My older brother, the former captain, vanished after laying down the Virgo Sword.","TWN":"我的哥哥曾是騎士團團長，但由於某種原因，他放下了布林加夫之劍，消失了蹤跡。"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"이상적인 기사였던 그의 뒤를 쫓는다면, 제가 잃어버린 것에 관한 답을 찾을 수 있을지도 모르죠.","JPN":"理想的な騎士だった兄の背中を追えば、私が失ったものに関する答えが見つかるかもしれません。","ENG":"If I follow the path of the ideal knight he once was, maybe I'll find the answer to what I lost.","TWN":"如果追隨那位理想騎士的腳步，也許我能找到關於我失去的東西的答案。"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"주제넘은 발언이네만, 난 세상에 온전한 정의는 없다고 생각하네.","JPN":"差し出がましいことを言うが、私はこの世に完全なる正義はないと思っている。","ENG":"This may be presumptuous, but I don't believe pure justice exists in this world.","TWN":"雖然這話有些冒昧，但我認為這個世界上沒有絕對的正義。"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"자네의 증오 역시 정당하지. 세계를 지키는 관리국이라도 결백하지만은 않거든.","JPN":"君の恨みも正当なものだ。世界を守る管理局も、潔白ではないのでね。","ENG":"Even your anger is justified. The Administration isn't without its sins.","TWN":"你的憎恨也是有道理的。即使是守護世界的管理局，也並非完全無辜。"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"지금의 제 행동이… 무의미하다는 말씀입니까?","JPN":"今の私の行動が……無意味だということですか？","ENG":"Are you saying what I'm doing now... is meaningless?","TWN":"你是說我現在的行動……毫無意義嗎？"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"알 수 없네. 인간이란 본디 부족한 존재로 태어나 끊임없이 벽에 부딪히는 법이거든.","JPN":"わからない。人間とは本来、欠如した存在として生まれるがゆえに、常に壁にぶつかるものだからな。","ENG":"I don't know. We humans are born flawed and always run into walls.","TWN":"無法知道。人類本來就是不完美的存在，總是不斷地撞上牆壁。"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"내가 내린 답이 자네에게 오답이듯 타인이 내린 결론만으론 정답에 다다를 수 없겠지.","JPN":"私が見出した答えが君にとっては不正解だったように、他人の結論だけでは答えにたどり着けない。","ENG":"Just as my answer might be wrong for you, no one else's answer can be your truth either.","TWN":"就像我給出的答案對你來說是錯誤的一樣，單憑他人得出的結論也無法達到正確答案吧。"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"……하지만, 지금의 제겐 이 길 밖엔 없습니다.","JPN":"……ですが、今の私にはこの道しかないのです。","ENG":"...Still, this is the only path I have right now.","TWN":"……但是，現在的我只有這條路可走。"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"자네를 나무라는 게 아니야. 이 또한 <color=#ffd34c>옛 인연</color>의 말을 인용한 불확실한 결론에 불과하거든.","JPN":"君を責めているわけではない。これもまた<color=#ffd34c>昔なじみ</color>の言葉を引用した、不確かな結論に過ぎないんだ。","ENG":"I'm not blaming you. This is just a borrowed thought from an <color=#ffd34c>old friend</color>.","TWN":"我不是在責備你。這也不過是引用<color=#ffd34c>舊緣</color>的話得出的不確定結論罷了。"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그러니 이건 관리자로서 하는 말이라기보다는… 그래.","JPN":"だからこれは管理者としての言葉ではなく……そうだな。","ENG":"So take it not as advice from an Administrator, but...","TWN":"所以這不是作為管理者的發言……是的。"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>현자</color>의 조언이라 생각해주게.","JPN":"<color=#ffd34c>賢者</color>のアドバイスだと思ってくれ。","ENG":"A <color=#ffd34c>Sage</color>'s counsel, if you will.","TWN":"<color=#ffd34c>智者</color>的建議，請考慮一下。"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"어라. 다른 팀원들은?","JPN":"あれ、他のメンバーは？","ENG":"Huh? Where's everyone else?","TWN":"咦，其他隊員呢？"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"다른 손님이었네. 노엘 양이야말로 어디를 간 건가?","JPN":"別の客だった。ノエル君こそどこに行ったんだ？","ENG":"It was a different visitor. But where is Noelle?","TWN":"原來是其他客人啊。洛艾兒到底去了哪裡呢？"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"펠리세트랑 이야기하러. 경기 시작 전에 전략을 짠다는 모양이야.","JPN":"フェリセットと話しに。試合前に戦略を練るらしいよ。","ENG":"She went to talk with Félicette. Said they were working out their strategy before the match.","TWN":"去找費莉塞特聊聊。應該是在比賽開始前制定策略。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"이건 정비공 아저씨 ID 넘버네. 사장님을 찾았다는 손님이 아저씨였어?","JPN":"これ、整備工のおじさんのIDカードだね。社長を探してた人って、おじさんだったの？","ENG":"This is the ID number of the mechanic. So the person asking for you was that old guy?","TWN":"這是修理工叔叔的ID號碼。找到老闆的客人是叔叔嗎？"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"굳이 따지면 옛 지인의 가족에 가깝겠지.","JPN":"しいて言うなら、古い知人の家族かな。","ENG":"Technically, I'd say they're more like family to an old acquaintance.","TWN":"如果非要說的話，應該算是舊友的家人吧。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"이전 일에 대한 고민이 많아 보이길래 작은 조언을 해주었네.","JPN":"前の件で悩んでいるようだったから、ちょっとしたアドバイスをしてやったよ。","ENG":"They seemed to be struggling with past regrets, so I gave them a bit of advice.","TWN":"看起來你對過去的事情有很多煩惱，所以我給了你一些小建議。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"이번에도 뒤에서 이상한 일 꾸미는 거 아니지?","JPN":"今回も、裏で何か変なこと計画してるんじゃないよね？","ENG":"You're not up to something shady again, right?","TWN":"這次不會又在背後搞什麼奇怪的事情吧？"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그리 말하면 내가 흑막 같지 않나.","JPN":"そう言われると、まるで私が黒幕のようではないか。","ENG":"Now that just makes me sound like the villain.","TWN":"這麼說的話，我不就像是幕後黑手了嗎。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"아니었어?","JPN":"違った？","ENG":"Aren't you?","TWN":"不是嗎？"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"그런데 의외네. 사장님 성격상 말만 하고 끝낼 것 같지는 않은데.","JPN":"でも意外だね。社長のことだから、口だけで終わるとは思えないけど。","ENG":"Still, that's surprising. You don't usually stop at just giving advice.","TWN":"不過真意外。以老闆的性格，應該不會只是說說而已吧。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"모든 일에는 주역이 있는 법일세. 그녀의 이야기에 내 조력은 필요치 않아.","JPN":"何事にも主役がいるものだ。彼女の物語に私の手助けは要らない。","ENG":"Every story has its lead. Mine isn't needed in hers.","TWN":"所有事情都有主角。她的故事不需要我的説明。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그러니 지켜볼 뿐이야. 그들이라면 분명, 그녀를 올바른 길로 인도해줄 테니까.","JPN":"だから見守るだけだ。彼らならきっと、彼女を正しい道へと導いてくれるだろう。","ENG":"So I'll just watch from the sidelines. If anyone can guide her to the right path, it's them.","TWN":"所以我只是靜觀其變。因為他們一定會引導她走上正確的道路。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"만났다는 사람이 여자였어?","JPN":"さっきの人って女だったの？","ENG":"The person you met was a woman?","TWN":"你見到的人是個女生嗎？"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"……지금 그게 중요한가?","JPN":"……今気にするところかね？","ENG":"...Is that what matters right now?","TWN":"……這個嘛，現在這個重要嗎？"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"사장님! 관계자분이 추가 멤버가 도착했대요!","JPN":"社長！　追加メンバーが到着したんですって！","ENG":"Boss! One of the staff said the extra member arrived!","TWN":"老闆！相關人員說新成員已經到了！"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"빨리 가봐요! 저, 누가 왔을 지 엄~청 궁금해지기 시작했어요!","JPN":"早く行きましょう！　誰が来たのかす～っごく気になります！","ENG":"We better go! I'm super curious to see who it is!","TWN":"快去看看！我、我開始好奇是誰來了！"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"뛰지 마요, 노엘. 그러다 넘어지면 경기할 때 지장 간다고요.","JPN":"走らないでください、ノエル。転んだら試合に響きますよ。","ENG":"Don't run, Noelle. If you trip and get hurt, it'll mess up the match.","TWN":"不要跑，洛艾兒。要是摔倒了，比賽時會有影響的。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L26_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"네-엡! 이 노엘. 들뜬 마음을 사뿐사뿐하게 표현해 보겠습니다!","JPN":"はいっ！　ノエル、浮かれた気持ちをふわふわな足取りで表現します！","ENG":"Okay! I, Noelle, shall express my excitement with gentle footsteps!","TWN":"是-嗯！我是洛艾兒。讓我輕輕地表達一下激動的心情吧！"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L30_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"다른 이야기는 잠시 접어두지. 우리도 나름대로 해야 할 일이 있으니까.","JPN":"この話は一旦ここまでにしよう。私たちにもやるべきことがあるのだから。","ENG":"Let's set this aside for now. We all have our roles to play.","TWN":"暫時擱置其他事情吧。我們也有自己的任務要完成。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"지금은 각자의 위치에서 최선을 다해보세.","JPN":"今はそれぞれの居場所で、全力を尽くしてみよう。","ENG":"So let's each give it our best, wherever we stand.","TWN":"現在請在各自的位置上盡力而為吧。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그리하면, 언젠가 스쳐 지나간 우연조차 필연으로 변모하는 순간이 올 거야.","JPN":"そうすれば、すれ違った偶然すらも必然に変わる瞬間が訪れるはずだ。","ENG":"That way, even fleeting coincidences can one day become inevitable.","TWN":"這樣的話，總有一天，連偶然擦肩而過的瞬間也會變成必然。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"무슨 소리인지는 모르겠지만…….","JPN":"何を言ってるのかはわからないけど……","ENG":"I have no idea what you're talking about...","TWN":"我不知道你在說什麼……"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"그래.","JPN":"わかった。","ENG":"But sure.","TWN":"好的。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L36_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"사장님이 그렇다면 그런 거겠지.","JPN":"社長がそう言うなら、そうなんだろうね。","ENG":"If you say so, Boss. Then I'll go along with it.","TWN":"如果老闆這麼說，那就是這樣了。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_LAUGH"},"R":null}}}]`);export{e as default};